package com.hiliving.content.banner;
import com.hiliving.api.ApiResponse;import jakarta.validation.Valid;import jakarta.validation.constraints.Positive;import org.springframework.http.*;import org.springframework.validation.annotation.Validated;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController class PublicBannerController{private final BannerService service;PublicBannerController(BannerService service){this.service=service;}@GetMapping("/api/v1/banners")ApiResponse<List<BannerResponse>> list(){return ApiResponse.of(service.publicList());}}
@Validated @RestController @RequestMapping("/api/v1/admin/banners") class AdminBannerController{private final BannerService service;AdminBannerController(BannerService service){this.service=service;}@GetMapping ApiResponse<List<BannerResponse>> list(){return ApiResponse.of(service.adminList());}@GetMapping("/{id}")ApiResponse<BannerResponse> find(@PathVariable @Positive Long id){return ApiResponse.of(service.find(id));}@PostMapping @ResponseStatus(HttpStatus.CREATED)ApiResponse<BannerResponse> create(@Valid @RequestBody BannerRequest r){return ApiResponse.of(service.create(r));}@PatchMapping("/{id}")ApiResponse<BannerResponse> update(@PathVariable @Positive Long id,@Valid @RequestBody BannerRequest r){return ApiResponse.of(service.update(id,r));}@DeleteMapping("/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)void delete(@PathVariable @Positive Long id){service.delete(id);}}
